css:
.wrapper .kpi-band-snapshot-pl {
  --surface-pl: var(--block-bg-color, #15151A);
  --surface-raised-pl: #1B1B22;
  --ink-pl: var(--color-text, #F4F4F7);
  --muted-pl: var(--color-gray-500, #8A8A96);
  --line-pl: var(--color-gray-200, rgba(255,255,255,.07));
  --accent-pl: var(--color-primary, #FFD21E);
  --accent2-pl: var(--color-secondary, #FF3D8B);
  --success-pl: var(--color-success, #36D399);
  --warning-pl: #F6C453;
  --danger-pl: var(--color-danger, #FF5A6E);
  container-type: inline-size;
  color: var(--ink-pl);
  font-family: var(--font-stack-primary, 'Inter', system-ui, -apple-system, 'Segoe UI', Roboto, sans-serif);
}

.wrapper .kpi-band-snapshot-pl .kpis-pl {
  display: grid;
  grid-template-columns: repeat(6, minmax(0, 1fr));
  gap: 14px;
}

.wrapper .kpi-band-snapshot-pl .kpi-pl {
  box-sizing: border-box;
  min-width: 0;
  display: flex;
  flex-direction: column;
  background: var(--surface-pl);
  border: 1px solid var(--line-pl);
  border-radius: 14px;
  padding: 16px;
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5);
  transition: background-color .16s ease, border-color .16s ease, box-shadow .16s ease;
}
.wrapper .kpi-band-snapshot-pl .kpi-pl:hover {
  background: var(--surface-raised-pl);
  border-color: color-mix(in srgb, var(--accent-pl) 28%, var(--line-pl));
}

.wrapper .kpi-band-snapshot-pl .kpi-pl.is-hero {
  border-color: color-mix(in srgb, var(--accent-pl) 42%, var(--line-pl));
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5), 0 0 26px -8px color-mix(in srgb, var(--accent-pl) 60%, transparent);
}
.wrapper .kpi-band-snapshot-pl .kpi-pl.is-hero:hover {
  border-color: color-mix(in srgb, var(--accent-pl) 60%, var(--line-pl));
  box-shadow: 0 1px 0 rgba(255,255,255,.03) inset, 0 6px 18px rgba(0,0,0,.5), 0 0 34px -8px color-mix(in srgb, var(--accent-pl) 72%, transparent);
}

.wrapper .kpi-band-snapshot-pl .label-pl {
  display: flex;
  align-items: center;
  gap: 7px;
  min-width: 0;
  overflow-wrap: break-word;
  font: 700 11px/1.2 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: .13em;
  text-transform: uppercase;
  color: var(--muted-pl);
}
.wrapper .kpi-band-snapshot-pl .dot-pl {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: var(--accent-pl);
  flex: none;
}
.wrapper .kpi-band-snapshot-pl .dot-pl.alt { background: var(--accent2-pl); }
.wrapper .kpi-band-snapshot-pl .kpi-pl.is-hero .dot-pl {
  box-shadow: 0 0 0 3px color-mix(in srgb, var(--accent-pl) 18%, transparent);
}

.wrapper .kpi-band-snapshot-pl .value-pl {
  font: 800 26px/1.1 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  letter-spacing: -.01em;
  font-variant-numeric: tabular-nums;
  color: var(--ink-pl);
  margin-top: 10px;
  min-width: 0;
  overflow-wrap: break-word;
}
.wrapper .kpi-band-snapshot-pl .ctx-pl {
  font: 600 11px/1.3 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
  font-variant-numeric: tabular-nums;
  color: var(--muted-pl);
  margin-top: 6px;
  overflow-wrap: break-word;
}

.wrapper .kpi-band-snapshot-pl .bar-pl {
  margin-top: 12px;
  height: 6px;
  border-radius: 4px;
  background: rgba(255,255,255,.06);
  overflow: hidden;
}
.wrapper .kpi-band-snapshot-pl .bar-pl > span {
  display: block;
  height: 100%;
  border-radius: 4px;
  background: var(--accent-pl);
}
.wrapper .kpi-band-snapshot-pl .bar-pl.good > span { background: var(--success-pl); }
.wrapper .kpi-band-snapshot-pl .bar-pl.ok > span { background: var(--warning-pl); }
.wrapper .kpi-band-snapshot-pl .bar-pl.low > span { background: var(--danger-pl); }

.wrapper .kpi-band-snapshot-pl .empty-pl {
  grid-column: 1 / -1;
  box-sizing: border-box;
  padding: 28px 24px;
  text-align: center;
  color: var(--muted-pl);
  background: var(--surface-pl);
  border: 1px solid var(--line-pl);
  border-radius: 14px;
  font: 500 13px/1.4 var(--font-stack-primary, 'Inter', system-ui, sans-serif);
}

@container (max-width: 1100px) {
  .wrapper .kpi-band-snapshot-pl .kpis-pl { grid-template-columns: repeat(3, minmax(0, 1fr)); }
}
@container (max-width: 640px) {
  .wrapper .kpi-band-snapshot-pl .kpis-pl { grid-template-columns: repeat(2, minmax(0, 1fr)); }
}
@container (max-width: 360px) {
  .wrapper .kpi-band-snapshot-pl .kpis-pl { grid-template-columns: 1fr; }
}

@media (prefers-reduced-motion: reduce) {
  .wrapper .kpi-band-snapshot-pl .kpi-pl { transition: none; }
}
